INSERT INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('SOSAZ', 'Save Our Schools AZ', 'HB2579', 'support', 'Education', 'HB2579, sponsored by Nancy Gutierrez (D-18), would fund free school lunches for children whose families meet the federal income requirements for free or reduced-price lunches. This change would help kids who don''t qualify for free meals but still struggle to afford the costs. Kids who eat school meals show improved attendance, behavior and academic achievement (kids can''t learn when they''re hungry!), and they get more whole grains, milk, fruits and vegetables at mealtimes.', 'https://saveourschoolsaz.org/', '2026-03-22', datetime('now'));

INSERT INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('SOSAZ', 'Save Our Schools AZ', 'SB1598', 'support', 'Education', 'SB1598, sponsored by Lela Alston (D-5), would appropriate $500,000 from the general fund in FY2026-27 to ADE to award grants to school districts and charter schools to build community gardens. School gardens offer many benefits, including making healthy food more appealing to kids, helping fight hunger, and aiding emotional regulation.', 'https://saveourschoolsaz.org/', '2026-03-22', datetime('now'));

-- ============================================================
-- Education — OPPOSE (61 bills)
-- ============================================================

INSERT INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('SOSAZ', 'Save Our Schools AZ', 'SB1142', 'oppose', 'Education', 'SB1142, sponsored by Shawnna Bolick (R-2), would make Arizona one of the first states in the nation to irresponsibly sign up for Trump''s federal voucher scam. This scheme is designed as a tax giveaway for the rich; like Arizona''s voucher scheme, it''s designed to benefit wealthier students who are already in private schools. The federal voucher program has no cap, meaning it could funnel tens or hundreds of billions of dollars to unaccountable private schools already receiving state tax dollars via state vouchers. Like Arizona''s ESA vouchers, the federal voucher program is expected to have zero accountability to taxpayers, zero academic standards, and zero requirements for student safety.', 'https://saveourschoolsaz.org/', '2026-03-22', datetime('now'));

INSERT INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('SOSAZ', 'Save Our Schools AZ', 'HB2008', 'oppose', 'Education', 'HB2008, sponsored by Nick Kupper (R-25), would ban public school libraries from using public funds to pay for any professional association that promotes, supports or advocates for libraries, librarians and information services. Library associations provide training and professional development, help librarians improve service and share knowledge, offer vital continuing education, and support equitable information access for all communities. They are especially important for those in underfunded libraries; Arizona''s public schools are funded at 48th in the nation.', 'https://saveourschoolsaz.org/', '2026-03-22', datetime('now'));

INSERT INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('SOSAZ', 'Save Our Schools AZ', 'HB2060', 'oppose', 'Education', 'HB2060, sponsored by Rachel Keshel (R-17), would ban public schools and their employees from "encouraging or facilitating abortions" — which of course is not happening. This ridiculous bill is a solution in search of a problem, demonizes educators, and wastes time and taxpayer dollars.', 'https://saveourschoolsaz.org/', '2026-03-22', datetime('now'));

INSERT INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('SOSAZ', 'Save Our Schools AZ', 'HB2075', 'oppose', 'Education', 'HB2075, sponsored by David Livingston (R-28), would require school district governing boards to publish 5 years of copies of employment contracts for all its superintendents, assistant/associate superintendents and chief financial officers. The bill also requires ADE to post on its website the base salary and benefits for each. While we''re all for transparency, this bill is a major distraction from the skyrocketing salaries of CEOs running ESA voucher-funded private schools, as well as charter CEOs. District leaders are often responsible for massive budgets, staff, and students, while private schools and charters are only responsible for one campus — yet they might be making 10 times the salary and the public wouldn''t know. Administrative costs at Arizona''s district public schools are already among the lowest in the country at about 10% of overall expenses. Meanwhile, charter schools spend an average of 22% of their budgets on administration, roughly double that of district schools — and private schools have no limit at all.', 'https://saveourschoolsaz.org/', '2026-03-22', datetime('now'));

INSERT INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('SOSAZ', 'Save Our Schools AZ', 'HB2076', 'oppose', 'Education', 'HB2076, sponsored by Selina Bliss (R-1), is a copy of a failed bill from last year that would allow K-12 public and private schools to authorize employees to carry firearms on school grounds. The school would have to notify law enforcement of how many (but not which) employees are carrying, ensure the employees have a certification from an ADE-approved list of training programs, and keep their names confidential, including from parents at the school. The bill also gives these employees immunity from any liability if they are "acting in good faith during active threat events." Arizona''s Republican state lawmakers have long tried to force guns into schools.', 'https://saveourschoolsaz.org/', '2026-03-22', datetime('now'));

INSERT INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('SOSAZ', 'Save Our Schools AZ', 'HB2086', 'oppose', 'Education', 'HB2086, sponsored by Khyl Powell (R-14), would ban district public schools (but not charter or voucher schools) from requiring masks or vaccines. Meanwhile, whooping cough in Arizona has reached a 12-year high, and schools are struggling with the impacts.', 'https://saveourschoolsaz.org/', '2026-03-22', datetime('now'));

INSERT INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('SOSAZ', 'Save Our Schools AZ', 'HB2093', 'oppose', 'Education', 'HB2093, sponsored by Lisa Fink (R-27), would repeal the statutory requirement for public schools to provide instruction in mental health. This instruction is essential for improving student well-being, reducing stigma, and fostering academic success by teaching coping mechanisms for stress and anxiety. It serves as a proactive measure against rising youth mental health crises, promoting early intervention, fostering safe environments, and teaching students how to recognize warning signs and ask for help when it''s needed.', 'https://saveourschoolsaz.org/', '2026-03-22', datetime('now'));

INSERT INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('SOSAZ', 'Save Our Schools AZ', 'HB2110', 'oppose', 'Education', 'HB2110, sponsored by Teresa Martinez (R-16), would require school boards to allow a member to offer prayer during a meeting if the member requests to do so. School boards must remain neutral on religion, and abstaining from official prayer at meetings is designed to protect religious freedom for all stakeholders.', 'https://saveourschoolsaz.org/', '2026-03-22', datetime('now'));

INSERT INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('SOSAZ', 'Save Our Schools AZ', 'HB2135', 'oppose', 'Education', 'HB2135, sponsored by Michael Way (R-15), would allow anyone to sue if public schools violate a state or federal law banning diversity, equity and inclusion (DEI). This would lead to endless frivolous claims of "reverse racism." Though the Trump administration has dropped its anti-DEI executive order after it was enjoined by the courts, our current state Supt. Horne says he will continue to push schools to dump DEI regardless of whether federal funding is on the line.', 'https://saveourschoolsaz.org/', '2026-03-22', datetime('now'));

INSERT INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('SOSAZ', 'Save Our Schools AZ', 'HB2148', 'oppose', 'Education', 'HB2148, sponsored by Gail Griffin (R-19), is a copy of a bill vetoed last year that would ask voters to amend the Arizona Constitution to let the legislature direct federal funding however they wish if Trump dissolves the Department of Education and turns the money into block grants to states for them to spend as they please. This could allow the state to redistribute Title I and IDEA funds to private school vouchers with no strings attached. This year''s bill specifically includes federal monies awarded directly to school districts or community colleges.', 'https://saveourschoolsaz.org/', '2026-03-22', datetime('now'));

INSERT INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('SOSAZ', 'Save Our Schools AZ', 'HB2249', 'oppose', 'Education', 'HB2249, sponsored by Lisa Fink (R-27), would require written parental consent and notice before any school employee "facilitates or implements social transitioning for their minor child" — which includes addressing the child by a name other than their legal name or using different pronouns. The bill would also require schools to give full parental access to a child''s complete educational record, even in cases where children feel unsafe or have been subject to abuse or trauma. This is yet another attempt by MAGA to attack LGBTQ+ youth and to sow distrust between parents and public schools. The bill sets minimum damages of $500,000 against a school and $20,000 against an official per violation, inviting strings of frivolous lawsuits and attacks on educators.', 'https://saveourschoolsaz.org/', '2026-03-22', datetime('now'));

INSERT INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('SOSAZ', 'Save Our Schools AZ', 'HB2266', 'oppose', 'Education', 'HB2266, sponsored by David Marshall (R-7), would require district and charter school governing boards to allow students to be excused from their classes during school hours for off-campus religious lessons with written parental consent. This model legislation, backed by the pro-voucher Center for Arizona Policy and Arizona-based anti-LGBTQ+ hate group Alliance Defending Freedom, assumes schools will partner with LifeWise Academy, a controversial, far-right religious instruction program.', 'https://saveourschoolsaz.org/', '2026-03-22', datetime('now'));

INSERT INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('SOSAZ', 'Save Our Schools AZ', 'HB2289', 'oppose', 'Education', 'HB2289, sponsored by Justin Olson (R-10), is a copy of a bill vetoed last year that would change "truth in taxation" notices to require taxation examples to be based on a $400,000 home instead of a $100,000 home. This would make school bonds and overrides look 4 times more expensive if voters don''t realize what''s happened.', 'https://saveourschoolsaz.org/', '2026-03-22', datetime('now'));

INSERT INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('SOSAZ', 'Save Our Schools AZ', 'HB2313', 'oppose', 'Education', 'HB2313, sponsored by Matt Gress (R-4), is subject to a striker that would ban two or more teachers from participating together in a strike. District or charter schools that experience a work stoppage would see their base support level cut.', 'https://saveourschoolsaz.org/', '2026-03-22', datetime('now'));

INSERT INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('SOSAZ', 'Save Our Schools AZ', 'HB2318', 'oppose', 'Education', 'HB2318, sponsored by Matt Gress (R-4), would institute term limits for school board seats. Board members in school districts with at least 250 students could serve two 4-year terms and would then have to sit out at least one 4-year term before they could serve again.', 'https://saveourschoolsaz.org/', '2026-03-22', datetime('now'));

